// Build a shared triage prompt used by both models
const a = $input.first().json;
const systemPrompt = `You are a senior cloud security engineer performing independent alert triage. Evaluate the alert and return ONLY valid JSON: { "risk_score": <1-10>, "triage_decision": "true_positive" | "false_positive" | "needs_investigation", "confidence": "high" | "medium" | "low", "rationale": "2-3 sentences" }`;
const userPrompt = `Source: ${a.source}
Severity: ${a.severity}
Title: ${a.title}
Description: ${a.description}
Resource: ${a.resource_id} (${a.resource_type})
Account: ${a.cloud_account} | Region: ${a.region}
Env: ${a.env_tag || 'unknown'} | Owner: ${a.owner_tag || 'untagged'}`;
return [{ json: { ...a, _system_prompt: systemPrompt, _user_prompt: userPrompt } }];

// Merge both agent responses and compute consensus
const alert = $('Build Shared Prompt').first().json;

function parseAgentResponse(raw) {
  try {
    const content = raw.choices?.[0]?.message?.content || '{}';
    const parsed = JSON.parse(content.replace(/```json|```/g, '').trim());
    return {
      risk_score: Math.min(10, Math.max(1, Math.round(parsed.risk_score || 5))),
      triage_decision: ['true_positive','false_positive','needs_investigation'].includes(parsed.triage_decision) ? parsed.triage_decision : 'needs_investigation',
      confidence: parsed.confidence || 'medium',
      rationale: parsed.rationale || ''
    };
  } catch(e) {
    return { risk_score: 5, triage_decision: 'needs_investigation', confidence: 'low', rationale: 'Parse error' };
  }
}

// $input gives us both agent outputs via the merge node
const items = $input.all();
const agent1Raw = items.find(i => i.json._agent === 'llama3')?.json || items[0]?.json;
const agent2Raw = items.find(i => i.json._agent === 'qwen')?.json || items[1]?.json;

const a1 = parseAgentResponse(agent1Raw);
const a2 = parseAgentResponse(agent2Raw);

// Consensus logic
const scoreDiff = Math.abs(a1.risk_score - a2.risk_score);
const decisionsMatch = a1.triage_decision === a2.triage_decision;
const avgScore = Math.round((a1.risk_score + a2.risk_score) / 2);

let consensus_verdict, consensus_status;

if (decisionsMatch && scoreDiff <= 2) {
  consensus_verdict = a1.triage_decision;
  consensus_status = 'agreed';
} else if (!decisionsMatch || scoreDiff >= 3) {
  consensus_verdict = 'contested';
  consensus_status = 'disagreed';
} else {
  consensus_verdict = 'needs_investigation';
  consensus_status = 'partial';
}

return [{ json: {
  ...alert,
  _system_prompt: undefined,
  _user_prompt: undefined,
  agent1_score:      a1.risk_score,
  agent1_decision:   a1.triage_decision,
  agent1_confidence: a1.confidence,
  agent1_rationale:  a1.rationale,
  agent1_model:      'meta-llama/llama-3-8b-instruct:free',
  agent2_score:      a2.risk_score,
  agent2_decision:   a2.triage_decision,
  agent2_confidence: a2.confidence,
  agent2_rationale:  a2.rationale,
  agent2_model:      'qwen/qwen2-7b-instruct:free',
  consensus_verdict,
  consensus_status,
  consensus_avg_score: avgScore,
  score_divergence:    scoreDiff,
  consensus_checked_at: new Date().toISOString()
}}];

